import React from 'react';
import { useNavigate } from 'react-router-dom';
import { FaCarSide, FaHeadset, FaQuestionCircle } from 'react-icons/fa';

const Support = () => {
    const navigate = useNavigate();

    return (
        <div style={containerStyle}>
            <aside style={sidebarStyle}>
                <div style={logoContainer}>
                    <FaCarSide style={carIconStyle} />
                    <h1 style={logoTextStyle}>Ucab</h1>
                </div>
                <nav style={{ flex: 1 }}>
                    <div onClick={() => navigate('/profile')} style={navItemStyle}>👤 Profile</div>
                    <div onClick={() => navigate('/booking')} style={navItemStyle}>🚗 Book a Ride</div>
                    <div onClick={() => navigate('/payments')} style={navItemStyle}>💳 Payments</div>
                    <div onClick={() => navigate('/support')} style={activeNavItemStyle}>⚙️ Support</div>
                </nav>
            </aside>

            <main style={mainAreaStyle}>
                <h2 style={{ fontWeight: '700', marginBottom: '30px' }}>Ucab Support Center</h2>
                
                <div style={cardStyle}>
                    <h4 style={{ display: 'flex', alignItems: 'center', gap: '10px' }}><FaHeadset color="#0052cc" /> Contact Support</h4>
                    <p style={{ marginTop: '10px' }}>We are available 24/7 for your help.</p>
                    <div style={{ marginTop: '15px' }}>
                        <div style={contactItem}>📧 support@ucab.com</div>
                        <div style={contactItem}>📞 +1 800-UCAB-HELP</div>
                    </div>
                </div>

                <div style={cardStyle}>
                    <h4 style={{ display: 'flex', alignItems: 'center', gap: '10px' }}><FaQuestionCircle color="#0052cc" /> Frequently Asked Questions</h4>
                    <div style={faqItem}>How can I cancel my ride?</div>
                    <div style={faqItem}>What if I forgot my belongings in the cab?</div>
                    <div style={faqItem}>How is my fare calculated?</div>
                </div>
            </main>
        </div>
    );
};

// --- Styles (Same as Payments for consistency) ---
const containerStyle = { display: 'flex', height: '100vh', backgroundColor: '#f8f9fc', fontFamily: "'Segoe UI', sans-serif" };
const sidebarStyle = { width: '280px', backgroundColor: '#fff', padding: '40px 24px', borderRight: '1px solid #edf2f7', display: 'flex', flexDirection: 'column' };
const logoContainer = { display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '40px' };
const carIconStyle = { fontSize: '32px', color: '#0052cc' };
const logoTextStyle = { fontSize: '28px', fontWeight: 'bold', color: '#1e293b' };
const navItemStyle = { padding: '14px 16px', cursor: 'pointer', borderRadius: '8px', color: '#64748b', marginBottom: '8px' };
const activeNavItemStyle = { ...navItemStyle, backgroundColor: '#f0f7ff', color: '#0052cc', fontWeight: '600' };
const mainAreaStyle = { flex: 1, padding: '40px' };
const cardStyle = { backgroundColor: '#fff', padding: '30px', borderRadius: '20px', boxShadow: '0 4px 12px rgba(0,0,0,0.05)', marginBottom: '30px' };
const contactItem = { padding: '10px 0', fontSize: '15px', color: '#475569' };
const faqItem = { padding: '15px 0', borderBottom: '1px solid #f1f5f9', cursor: 'pointer', color: '#0052cc', fontWeight: '500' };

export default Support;
